using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1️⃣ GetTypeInfo<T>() — returns strongly-typed JsonTypeInfo<T>
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> → Type={personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Ada", 37), personInfo);
Console.WriteLine($"  Serialized: {json}");

// 2️⃣ TryGetTypeInfo<T>() — probe without throwing
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
{
    Console.WriteLine($"TryGetTypeInfo<Person> → resolved ({info!.Type.Name})");
}

// Now try a type that has NO resolver configured (use a restricted options instance)
var restricted = new JsonSerializerOptions
{
    TypeInfoResolver = null   // no resolver at all
};
restricted.MakeReadOnly();

if (restricted.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? missing))
{
    Console.WriteLine($"Unexpected: got info for Person → {missing!.Type.Name}");
}
else
{
    Console.WriteLine("TryGetTypeInfo<Person> on restricted options → not available (no exception!)");
}

public record Person(string Name, int Age);

